12	  const navigate = useNavigate();
13	  const { session } = useSession();
14	  const mutation = useCreateMarket();
15	
16	  const [title, setTitle] = useState("");
17	  const [description, setDescription] = useState("");
18	  const [expiresAt, setExpiresAt] = useState("");
19	  const [liquidity, setLiquidity] = useState("10000");
20	  const [outcomes, setOutcomes] = useState<OutcomeInput[]>([
21	    { id: "yes", name: "Yes" },
22	    { id: "no", name: "No" },
23	  ]);
24	
25	  const addOutcome = () => {
26	    const n = outcomes.length + 1;
27	    setOutcomes([...outcomes, { id: `o${n}`, name: `Option ${n}` }]);
28	  };
29	
30	  const removeOutcome = (idx: number) => {
31	    if (outcomes.length <= 2) return;
32	    setOutcomes(outcomes.filter((_, i) => i !== idx));
33	  };
34	
35	  const updateOutcome = (idx: number, field: keyof OutcomeInput, value: string) => {
36	    const next = [...outcomes];
37	    next[idx] = { ...next[idx]!, [field]: value };
38	    setOutcomes(next);
39	  };
40	
41	  const handleSubmit = (e: React.FormEvent) => {
42	    e.preventDefault();
43	    mutation.mutate(
44	      {
45	        payload: {
46	          title,
47	          description,
48	          outcomes,
49	          expires_at: new Date(expiresAt).toISOString(),
50	          liquidity: Number(liquidity) || 10000,
51	        },
52	        session: session.accountId ? session : undefined,
53	      },
54	      {
55	        onSuccess: (data) => {
56	          navigate(`/markets/${data.market.id}`);
57	        },
58	      },
59	    );
60	  };
61	
62	  const isValid = title.trim().length > 0 && expiresAt.length > 0 && outcomes.every((o) => o.id && o.name);
63	
64	  return (
65	    <div style={{ maxWidth: 600, margin: "0 auto" }}>
66	      <h1 style={{ fontSize: "1.5rem", fontWeight: 600, marginBottom: "var(--space-lg)" }}>
67	        Create Market
68	      </h1>
69	
70	      <form onSubmit={handleSubmit} style={{ display: "grid", gap: "var(--space-md)" }}>
71	        <label style={labelWrapStyle}>
72	          <span style={labelStyle}>Question / Title</span>
73	          <input
74	            type="text"
75	            value={title}
76	            onChange={(e) => setTitle(e.target.value)}
77	            placeholder="Will ETH trade above $5000 by December?"
78	            style={inputStyle}
79	            required
80	          />
81	        </label>
82	
83	        <label style={labelWrapStyle}>
84	          <span style={labelStyle}>Description (optional)</span>
85	          <textarea
86	            value={description}
87	            onChange={(e) => setDescription(e.target.value)}
88	            placeholder="Additional context about resolution criteria..."
89	            rows={3}
90	            style={{ ...inputStyle, resize: "vertical" }}
91	          />
92	        </label>
93	
94	        <div>
95	          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
96	            <span style={labelStyle}>Outcomes (min 2)</span>
97	            <button type="button" onClick={addOutcome} style={addBtnStyle}>+ Add outcome</button>
98	          </div>
99	          <div style={{ display: "grid", gap: "var(--space-sm)" }}>
100	            {outcomes.map((o, idx) => (
101	              <div key={idx} style={{ display: "grid", gridTemplateColumns: "1fr 2fr auto", gap: "var(--space-sm)" }}>
102	                <input
103	                  type="text"
104	                  value={o.id}
105	                  onChange={(e) => updateOutcome(idx, "id", e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, ""))}
106	                  placeholder="id"
107	                  style={{ ...inputStyle, fontFamily: "var(--font-mono)", fontSize: "0.8rem" }}
108	                />
109	                <input
110	                  type="text"
111	                  value={o.name}
112	                  onChange={(e) => updateOutcome(idx, "name", e.target.value)}
113	                  placeholder="Display name"
114	                  style={inputStyle}
115	                />
116	                <button
117	                  type="button"
118	                  onClick={() => removeOutcome(idx)}
119	                  disabled={outcomes.length <= 2}
120	                  style={removeBtnStyle}
121	                >
122	                  ×
123	                </button>
124	              </div>
